const katutaData = $items("Fetch Katuta Data")[0].json || {};
const hasRealData = Object.keys(katutaData).length > 0 && !katutaData.error;

// MOCK FALLBACK (If Katuta API is offline)
const mockReservations = [
  { Reserva_ID: 999, Nome_Cliente: 'Simulated User', Hora: '20:00', Qtd_Pessoas: 4, Mesa_ID: 'T-SIM', Status: 'Confirmed' }
];

const reservations = hasRealData ? (katutaData.reservations || []) : mockReservations;
const metrics = hasRealData ? katutaData.metrics : { total_reservas: 0, mesas_ocupadas: 0 };

// Generate Logs
const logs = [
  "Analyzing market trends...",
  "Connecting to WhatsApp API...",
  "Database backup complete.",
  "Verifying user credentials...",
  "Optimizing neural network weights...",
  "Ping: 24ms",
  "Agent heartbeat received."
];

if (hasRealData) {
    logs.push(`[KATUTA] Synced ${reservations.length} reservations from Sheets`);
    logs.push(`[KATUTA] Occupancy Rate: ${metrics.occupancy_rate || '0%'}`);
}

// Agents List
const agents = [
  { 
      id: 'katuta-core', 
      name: 'Katuta Main Brain', 
      status: 'active', 
      task: hasRealData ? `Monitoring ${reservations.length} reservations` : 'Connecting to Katuta API...', 
      type: 'CORE',
      data: { 
          reservations: reservations,
          metrics: metrics
      }
  },
  { id: 1, name: 'Sales Agent (WhatsApp)', status: Math.random() > 0.3 ? 'active' : 'idle', task: 'Negotiating with Client #' + Math.floor(Math.random() * 1000), type: 'WORKER' },
  { id: 2, name: 'Finance Agent', status: Math.random() > 0.5 ? 'active' : 'idle', task: 'Processing invoice #' + Math.floor(Math.random() * 500), type: 'WORKER' }
];

const randomLog = logs[Math.floor(Math.random() * logs.length)];

return [
  {
    json: {
      agents: agents,
      latestLog: {
        timestamp: new Date().toISOString(),
        message: randomLog,
        level: randomLog.includes('[KATUTA]') ? 'CORE' : 'INFO'
      }
    }
  }
];
